// Interface — 100% abstract (until Java 8+)
interface Drawable {
    // Constants (public static final by default)
    String DEFAULT_COLOR = "Black";

    // Abstract methods (public abstract by default)
    void draw();

    // Default method (Java 8+) — provides default implementation
    default void display() {
        System.out.println("Displaying with " + DEFAULT_COLOR + " color");
    }

    // Static method (Java 8+)
    static void info() {
        System.out.println("Drawable interface v1.0");
    }
}

interface Resizable {
    void resize(double factor);
}

// Class can implement multiple interfaces
class Circle implements Drawable, Resizable {
    double radius;
    String color;

    Circle(double radius) {
        this.radius = radius;
        this.color = Drawable.DEFAULT_COLOR;
    }

    @Override
    public void draw() {
        System.out.println("Drawing a circle with radius " + radius + " (color: " + color + ")");
    }

    @Override
    public void resize(double factor) {
        radius *= factor;
        System.out.println("Resized circle to radius " + radius);
    }

    // Override default method (optional)
    @Override
    public void display() {
        System.out.println("Custom display: Circle with radius " + radius);
    }
}

class Square implements Drawable {
    double side;

    Square(double side) {
        this.side = side;
    }

    @Override
    public void draw() {
        System.out.println("Drawing a square with side " + side);
    }
}

public class InterfaceExample {
    public static void main(String[] args) {
        Drawable.info();  // Call static interface method

        Circle circle = new Circle(5);
        Square square = new Square(4);

        circle.draw();
        circle.display();
        circle.resize(2);

        System.out.println("---");

        square.draw();
        square.display();  // Uses default implementation

        // Polymorphism with interfaces
        Drawable[] drawables = {circle, square};
        System.out.println("--- Drawing all ---");
        for (Drawable d : drawables) {
            d.draw();
        }
    }
}

